module top_module(
  input [3:0] a,
  input [3:0] b,
  output reg eq,
  output reg gt,
  output reg lt
);// Check for equality
    wire _n01 = a[0] ^ b[0];
  wire _n02 = a[1] ^ b[1];
  wire _n03 = a[2] ^ b[2];
  wire _n04 = a[3] ^ b[3];
  assign eq = ~_n01 & ~_n02 & ~_n03 & ~_n04;

  // Check for greater than
  always @* begin
    if (a > b)
      gt = 1;
    else
      gt = 0;
  end

  // Check for less than
  always @* begin
    if (a < b)
      lt = 1;
    else
      lt = 0;
  end

endmodule
